mapper.select:
select 
from agent_remediation_workflows
where agent_id = #{agentId}
order by updated_at desc, created_at desc
limit #{limit}

mapper.update:
update agent_remediation_workflows
set execution_lease_owner = null,
    execution_lease_acquired_at = null,
    execution_lease_expires_at = null,
    updated_at = #{now},
    version = version + 1
where workflow_id = #{workflowId}
  and execution_lease_owner = #{leaseOwner}
  and execution_lease_expires_at is not null
  and execution_lease_expires_at <= #{now}

mapper.insert:
insert into agent_remediation_workflow_history (
    history_id, workflow_id, agent_id, event_type, operator_id, reason, metadata, occurred_at
) values (
    #{record.historyId}, #{record.workflowId}, #{record.agentId}, #{record.eventType},
    #{record.operatorId}, #{record.reason}, coalesce(cast(#{record.metadataJson} as jsonb), '{}'::jsonb),
    #{record.occurredAt}
)

mapper.select:
select 
from agent_remediation_workflow_history
where event_type = #{eventType}
order by occurred_at desc, history_id desc
limit #{limit}
